     2→// Disassembler: 바이트코드를 읽을 수 있는 형태로 변환
     3→// ============================================================================
     4→
     5→use crate::bytecode::Bytecode;
     6→use crate::opcode::OpCode;
     7→
     8→/// 바이트코드를 인간이 읽을 수 있는 형태로 변환
     9→pub struct Disassembler;
    10→
    11→impl Disassembler {
    12→    /// 전체 바이트코드를 문자열로 변환
    13→    pub fn disassemble(bytecode: &Bytecode) -> String {
    14→        let mut output = String::new();
    15→        output.push_str("=== Bytecode Disassembly ===\n");
    16→        output.push_str("Instructions:\n");
    17→
    18→        let mut ip = 0;
    19→        while ip < bytecode.instructions.len() {
    20→            let instruction = bytecode.instructions[ip];
    21→            if let Some(opcode) = OpCode::from_byte(instruction) {
    22→                let (line, consumed) = Self::disassemble_instruction(bytecode, ip, opcode);
    23→                output.push_str(&format!("{:04} | {}\n", ip, line));
    24→                ip += consumed;
    25→            } else {
    26→                output.push_str(&format!("{:04} | UNKNOWN({})\n", ip, instruction));
    27→                ip += 1;
    28→            }
    29→        }
    30→
    31→        output.push_str("\n=== Constants ===\n");
    32→        for (idx, constant) in bytecode.constants.iter().enumerate() {
    33→            output.push_str(&format!("{:3} | {}\n", idx, constant));
    34→        }
    35→
    36→        output
    37→    }
    38→
    39→    /// 단일 명령어를 문자열과 소비한 바이트 수로 변환
    40→    fn disassemble_instruction(bytecode: &Bytecode, ip: usize, opcode: OpCode) -> (String, usize) {
    41→        let width = opcode.operand_width();
    42→
    43→        if width == 0 {
    44→            (format!("{}", opcode.name()), 1)
    45→        } else if width == 1 {
    46→            let operand = bytecode.instructions.get(ip + 1).copied().unwrap_or(0) as u16;
    47→            match opcode {
    48→                OpCode::OpGetLocal | OpCode::OpSetLocal | OpCode::OpCall => {
    49→                    (format!("{} {}", opcode.name(), operand), 2)
    50→                }
    51→                _ => (format!("{} {}", opcode.name(), operand), 2),
    52→            }
    53→        } else if width == 2 {
    54→            let high = bytecode.instructions.get(ip + 1).copied().unwrap_or(0) as u16;
    55→            let low = bytecode.instructions.get(ip + 2).copied().unwrap_or(0) as u16;
    56→            let operand = (high << 8) | low;
    57→
    58→            match opcode {
    59→                OpCode::OpConstant => {
    60→                    let constant = bytecode.get_constant(operand as usize).unwrap_or(0);
    61→                    (
    62→                        format!("{} {} ({})", opcode.name(), operand, constant),
    63→                        3,
    64→                    )
    65→                }
    66→                OpCode::OpJump | OpCode::OpJumpNotTruthy => {
    67→                    (format!("{} {:04}", opcode.name(), operand), 3)
    68→                }
    69→                OpCode::OpArray | OpCode::OpHash => {
    70→                    (format!("{} {}", opcode.name(), operand), 3)
    71→                }
    72→                _ => (format!("{} {}", opcode.name(), operand), 3),
    73→            }
    74→        } else {
    75→            (format!("{} (?)", opcode.name()), 1)
    76→        }
    77→    }
    78→
    79→    /// 정의된 OpCode 목록 출력
    80→    pub fn print_instructions() {
    81→        println!("=== Available Instructions ===");
    82→        let opcodes = vec![
    83→            OpCode::OpConstant,
    84→            OpCode::OpAdd,
    85→            OpCode::OpSub,
    86→            OpCode::OpMul,
    87→            OpCode::OpDiv,
    88→            OpCode::OpTrue,
    89→            OpCode::OpFalse,
    90→            OpCode::OpEqual,
    91→            OpCode::OpNotEqual,
    92→            OpCode::OpLessThan,
    93→            OpCode::OpGreaterThanOrEqual,
    94→            OpCode::OpBang,
    95→            OpCode::OpMinus,
    96→            OpCode::OpJump,
    97→            OpCode::OpJumpNotTruthy,
    98→            OpCode::OpNull,
    99→            OpCode::OpPop,
   100→            OpCode::OpReturnValue,
   101→            OpCode::OpReturn,
   102→            OpCode::OpGetLocal,
   103→            OpCode::OpSetLocal,
   104→            OpCode::OpArray,
   105→            OpCode::OpHash,
   106→            OpCode::OpIndex,
   107→            OpCode::OpCall,
   108→            OpCode::OpEnd,
   109→        ];
   110→
   111→        for op in opcodes {
   112→            println!(
   113→                "{:3} | {:<20} (width: {})",
   114→                op.as_byte(),
   115→                op.name(),
   116→                op.operand_width()
   117→            );
   118→        }
   119→    }
   120→}
   121→
   122→#[cfg(test)]
   123→mod tests {
   124→    use super::*;
   125→
   126→    #[test]
   127→    fn test_disassemble_simple() {
   128→        let mut bytecode = Bytecode::new();
   129→
   130→        // PUSH 5
   131→        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   132→        let idx = bytecode.add_constant(5);
   133→        bytecode.add_instruction((idx >> 8) as u8);
   134→        bytecode.add_instruction((idx & 0xFF) as u8);
   135→
   136→        // PUSH 3
   137→        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   138→        let idx = bytecode.add_constant(3);
   139→        bytecode.add_instruction((idx >> 8) as u8);
   140→        bytecode.add_instruction((idx & 0xFF) as u8);
   141→
   142→        // ADD
   143→        bytecode.add_instruction(OpCode::OpAdd.as_byte());
   144→
   145→        let output = Disassembler::disassemble(&bytecode);
   146→        assert!(output.contains("CONSTANT"));
   147→        assert!(output.contains("ADD"));
   148→        assert!(output.contains("5"));
   149→        assert!(output.contains("3"));
   150→    }
   151→
   152→    #[test]
   153→    fn test_disassemble_jump() {
   154→        let mut bytecode = Bytecode::new();
   155→
   156→        // PUSH true
   157→        bytecode.add_instruction(OpCode::OpTrue.as_byte());
   158→
   159→        // JUMP_NOT_TRUTHY 0x0005
   160→        bytecode.add_instruction(OpCode::OpJumpNotTruthy.as_byte());
   161→        bytecode.add_instruction(0x00);
   162→        bytecode.add_instruction(0x05);
   163→
   164→        let output = Disassembler::disassemble(&bytecode);
   165→        assert!(output.contains("TRUE"));
   166→        assert!(output.contains("JUMP_NOT_TRUTHY"));
   167→        assert!(output.contains("0005"));
   168→    }
   169→}
