### Step 6: vm.rs - 실행 루프 상세 구현 (질문 3 답변)

#### vm.rs 실행 루프의 상세 설계

```rust
// v15_2_vm_conditionals/src/vm.rs

use crate::bytecode::Bytecode;
use crate::opcode::OpCode;
use crate::value::Value;

pub struct VM {
    bytecode: Bytecode,
    stack: Vec<Value>,
    ip: usize,    // Instruction Pointer: 현재 실행 중인 바이트 위치
}
```

**실행 루프 설계의 핵심 결정사항**:

```rust
impl VM {
    pub fn new(bytecode: Bytecode) -> Self {
        VM {
            bytecode,
            stack: Vec::new(),
            ip: 0,
        }
    }

    pub fn run(&mut self) -> Result<Value, String> {
        while self.ip < self.bytecode.instructions.len() {
            let byte = self.bytecode.instructions[self.ip];
            let op = OpCode::from_byte(byte)
                .ok_or_else(|| format!("알 수 없는 OpCode: {}", byte))?;
            self.ip += 1; // op 바이트 소비

            match op {
                OpCode::OpConstant => {
                    let idx = self.read_u16() as usize;
                    let val = self.bytecode.constants.get(idx)
                        .ok_or_else(|| format!("상수 인덱스 {} 없음", idx))?;
                    self.stack_push(Value::Int(*val));
                }

                OpCode::OpAdd | OpCode::OpSub | OpCode::OpMul | OpCode::OpDiv => {
                    let right = self.stack_pop()?;
                    let left = self.stack_pop()?;
                    match (left, right) {
                        (Value::Int(l), Value::Int(r)) => {
                            let result = match op {
                                OpCode::OpAdd => l + r,
                                OpCode::OpSub => l - r,
                                OpCode::OpMul => l * r,
                                OpCode::OpDiv => {
                                    if r == 0 {
                                        return Err("0으로 나눌 수 없습니다".to_string());
                                    }
                                    l / r
                                }
                                _ => unreachable!(),
                            };
                            self.stack_push(Value::Int(result));
                        }
                        (l, r) => {
                            return Err(format!(
                                "산술 연산 타입 오류: {} 와 {}",
                                l.type_name(), r.type_name()
                            ));
                        }
                    }
                }

                OpCode::OpTrue => self.stack_push(Value::Bool(true)),
                OpCode::OpFalse => self.stack_push(Value::Bool(false)),
                OpCode::OpNull => self.stack_push(Value::Null),

                OpCode::OpEqual | OpCode::OpNotEqual => {
                    let right = self.stack_pop()?;
                    let left = self.stack_pop()?;
                    let result = match op {
                        OpCode::OpEqual => left == right,
                        OpCode::OpNotEqual => left != right,
                        _ => unreachable!(),
                    };
                    self.stack_push(Value::Bool(result));
                }

                OpCode::OpLessThan | OpCode::OpGreaterThanOrEqual => {
                    let right = self.stack_pop()?;
                    let left = self.stack_pop()?;
                    match (left, right) {
                        (Value::Int(l), Value::Int(r)) => {
                            let result = match op {
                                OpCode::OpLessThan => l < r,
                                OpCode::OpGreaterThanOrEqual => l >= r,
                                _ => unreachable!(),
                            };
                            self.stack_push(Value::Bool(result));
                        }
                        (l, r) => {
                            return Err(format!(
                                "비교 연산 타입 오류: {} 와 {}",
                                l.type_name(), r.type_name()
                            ));
                        }
                    }
                }

                OpCode::OpBang => {
                    let val = self.stack_pop()?;
                    self.stack_push(Value::Bool(!val.is_truthy()));
                }

                OpCode::OpMinus => {
                    let val = self.stack_pop()?;
                    match val {
                        Value::Int(n) => self.stack_push(Value::Int(-n)),
                        other => {
                            return Err(format!(
                                "음수 연산은 Int에만 적용: {}",
                                other.type_name()
                            ));
                        }
                    }
                }

                // ============================================================
                // [핵심] 점프 명령어들 - 비선형 실행의 핵심
                // ============================================================
                OpCode::OpJump => {
                    // 무조건 점프: 2바이트 절대 주소로 ip 이동
                    let target = self.read_u16() as usize;
                    self.ip = target;
                    // read_u16()이 ip를 +2 했지만, 점프이므로 target으로 덮어씀
                }

                OpCode::OpJumpNotTruthy => {
                    // 조건부 점프: 스택 top이 falsy면 점프
                    let target = self.read_u16() as usize;
                    let condition = self.stack_pop()?;
                    if !condition.is_truthy() {
                        self.ip = target;
                    }
                    // truthy면 read_u16()이 설정한 ip+2가 그대로 유지됨
                }

                OpCode::OpPop => {
                    self.stack_pop()?;
                }

                OpCode::OpArray => {
                    let count = self.read_u16() as usize;
                    // 스택에서 count개의 요소를 꺼내 배열 생성
                    // 주의: 스택은 LIFO이므로 역순으로 꺼내야 함
                    let mut elements = Vec::with_capacity(count);
                    for _ in 0..count {
                        elements.push(self.stack_pop()?);
                    }
                    elements.reverse(); // 원래 순서 복원
                    self.stack_push(Value::Array(elements));
                }

                OpCode::OpIndex => {
                    let index = self.stack_pop()?;
                    let array = self.stack_pop()?;
                    match (array, index) {
                        (Value::Array(arr), Value::Int(idx)) => {
                            if idx < 0 || idx as usize >= arr.len() {
                                self.stack_push(Value::Null);
                            } else {
                                self.stack_push(arr[idx as usize].clone());
                            }
                        }
                        (arr, idx) => {
                            return Err(format!(
                                "인덱스 타입 오류: {}[{}]",
                                arr.type_name(), idx.type_name()
                            ));
                        }
                    }
                }

                OpCode::OpEnd => {
                    break;
                }

                OpCode::OpReturnValue | OpCode::OpReturn
                | OpCode::OpGetLocal | OpCode::OpSetLocal
                | OpCode::OpHash | OpCode::OpCall => {
                    // v15.3에서 구현 예정
                    return Err(format!(
                        "{} 명령어는 v15.3에서 구현됩니다", op.name()
                    ));
                }
            }
        }

        // 실행 종료: 스택 top이 최종 결과
        if let Some(val) = self.stack.last() {
            Ok(val.clone())
        } else {
            Ok(Value::Null)
        }
    }

    // ================================================================
    // 헬퍼 메서드들
    // ================================================================

    /// ip에서 u16 읽기 (big-endian), ip += 2
    fn read_u16(&mut self) -> u16 {
        let high = self.bytecode.instructions[self.ip] as u16;
        let low = self.bytecode.instructions[self.ip + 1] as u16;
        self.ip += 2;
        (high << 8) | low
    }

    fn stack_push(&mut self, val: Value) {
        self.stack.push(val);
    }

    fn stack_pop(&mut self) -> Result<Value, String> {
        self.stack.pop().ok_or_else(|| "스택 언더플로우".to_string())
    }

    pub fn stack_peek(&self) -> Option<&Value> {
        self.stack.last()
    }

    /// 교육용: 스택 상태 출력
    pub fn stack_snapshot(&self) -> String {
        let items: Vec<String> = self.stack.iter().map(|v| v.to_string()).collect();
        format!("[{}]", items.join(", "))
    }
}
```

**OpJump 실행 루프에서의 ip 관리 주의점**:

`read_u16()`은 ip를 +2 증가시킵니다. OpJump의 경우 target으로 ip를 덮어쓰므로 read_u16()의 +2는 무시됩니다. OpJumpNotTruthy에서 조건이 truthy인 경우 read_u16()이 설정한 ip+2가 그대로 다음 명령어가 됩니다. 이 패턴이 올바르게 동작하는 이유: read_u16()을 호출하는 순간 이미 피연산자 2바이트를 소비한 상태이므로, truthy인 경우 정확히 다음 명령어를 가리킵니다.

